// Extract and validate upload payload
const body = $input.first().json.body || $input.first().json;
const { filename, fileBase64, mimeType } = body;

if (!filename || !fileBase64) {
  throw new Error('Missing filename or fileBase64 in request body');
}

return [{ json: { filename, fileBase64, mimeType: mimeType || 'application/octet-stream' } }];

// Chunk the extracted text and obtain embeddings from Ollama
// Then prepare Qdrant point objects for batch insertion

const { extractedText, id, collection, filename, textLength } = $input.first().json;

if (!extractedText || extractedText.trim().length < 10) {
  // No text – mark as ready with 0 chunks and skip embedding
  return [{ json: { docId: id, collection, totalChunks: 0, points: [], noText: true } }];
}

const CHUNK_SIZE = 500;
const OVERLAP    = 50;
const EMBED_MODEL = 'nomic-embed-text-v2-moe';
const OLLAMA_URL  = 'http://host.docker.internal:11434/api/embeddings';

// ── Chunk text ──────────────────────────────────────────────────────────────
const chunks = [];
for (let pos = 0; pos < extractedText.length; pos += (CHUNK_SIZE - OVERLAP)) {
  const text = extractedText.slice(pos, pos + CHUNK_SIZE).trim();
  if (text.length >= 20) chunks.push(text);
}

// Cap at 200 chunks to avoid n8n timeouts on huge documents
const cappedChunks = chunks.slice(0, 200);

// ── Generate embeddings ──────────────────────────────────────────────────────
const points = [];
for (let i = 0; i < cappedChunks.length; i++) {
  try {
    const resp = await fetch(OLLAMA_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: EMBED_MODEL, prompt: cappedChunks[i] }),
    });
    const data = await resp.json();
    if (data.embedding && data.embedding.length > 0) {
      points.push({
        id: Date.now() + i,   // unique numeric ID required by Qdrant
        vector: data.embedding,
        payload: {
          text:        cappedChunks[i],
          doc_id:      id,
          filename:    filename,
          chunk_index: i,
        },
      });
    }
  } catch (err) {
    console.error(`[chunk ${i}] embedding error: ${err.message}`);
  }
}

return [{ json: { docId: id, collection, totalChunks: cappedChunks.length, points } }];

// Only insert if we have embedding points to add
const { points, docId, collection, totalChunks, noText } = $input.first().json;

if (noText || !points || points.length === 0) {
  return [{ json: { docId, collection, totalChunks: 0, inserted: 0, skip: true } }];
}

return [{ json: { docId, collection, totalChunks, points, inserted: points.length } }];
